const items = $input.all();
const textToNumber = {
  uno: 1,
  dos: 2,
  tres: 3,
  cuatro: 4,
  cinco: 5,
  seis: 6,
  siete: 7,
  ocho: 8,
  nueve: 9,
  diez: 10,
};
const cleanedItems = items.map((item) => {
  const id = item.json.id[0];
  const cliente = item.json.cliente[0]
    .split(" ")
    .map((word) => word.charAt(0).toUpperCase() + word.slice(1).toLowerCase())
    .join(" ");
  const email = item.json.email[0].toLowerCase().trim().replace(",", ".");
  const cantidad = isNaN(Number(item.json.cantidad[0]))
    ? textToNumber[item.json.cantidad[0].toLowerCase()] || 1
    : Number(item.json.cantidad[0]);
  const monto =
    parseFloat(item.json.monto[0].replace(/[^0-9.,]/g, "").replace(",", ".")) ||
    0;
  const fecha = item.json.fecha[0].split("T")[0];
  const estado = item.json.estado[0]
    .split(" ")
    .map((word) => word.charAt(0).toUpperCase() + word.slice(1).toLowerCase())
    .join(" ");
  return { id, cliente, email, cantidad, monto, fecha, estado };
});

return cleanedItems;

for (const item of $input.all()) {
  let email = item.json.email || "";
  let fecha = item.json.fecha ? item.json.fecha.toString() : "";
  let monto = item.json.monto;

  // --- 1. VALIDACIÓN DE EMAIL (Sofia y otros) ---
  // Marcamos como inválido si tiene doble punto o si no cumple formato estándar
  const regexDoblePunto = /(\.\.)/;
  const regexEmailEstandar = /^[^\s@]+@[^\s@]+\.[^\s@]{2,}$/;

  if (regexDoblePunto.test(email) || !regexEmailEstandar.test(email)) {
    item.json.email_valido = false;
  } else {
    item.json.email_valido = true;
  }

  // --- 2, 3 y 4. NORMALIZACIÓN DE FECHA ---
  if (fecha) {
    // Reemplazar "/" por "-" y quitar hora/minuto/segundo (split por espacio o 'T')
    fecha = fecha.replace(/\//g, '-').split(/[ T]/)[0];

    // Manejar caso YYYYMMDD (ej: 20240121)
    if (/^\d{8}$/.test(fecha)) {
      fecha = `${fecha.substring(0, 4)}-${fecha.substring(4, 6)}-${fecha.substring(6, 8)}`;
    }

    item.json.fecha = fecha;
  }

  // --- EXTRA: LIMPIEZA DE MONTO ---
  // Aseguramos que el null sea 0 para que el Summarize no explote
  if (monto === null || isNaN(monto)) {
    item.json.monto = 0;
  }
}

return $input.all();
